+
+fn format_duration(ns: f64) -> String {
+    if ns >= 1_000_000.0 {
+        format!("{:.2}ms", ns / 1_000_000.0)
+    } else if ns >= 1_000.0 {
+        format!("{:.2}us", ns / 1_000.0)
+    } else {
