+/// Benchmarks Linux mmap (region_map equivalent).
+#[cfg(unix)]
+pub fn bench_linux_mmap(config: &LinuxBenchConfig) -> BenchmarkResult {
+    let mut measurements = Vec::with_capacity(config.measure_iterations);
+    let page_size = 4096usize;
