+//! Statistics utilities for benchmark analysis.
+//!
+//! Provides statistical functions for analyzing benchmark results.
+
+use hdrhistogram::Histogram;
+
+/// Statistical summary of measurements.
+#[derive(Debug, Clone)]
+pub struct Stats {
+    /// Number of samples.
+    pub count: u64,
+    /// Mean value.
+    pub mean: f64,
+    /// Median (p50).
+    pub median: f64,
+    /// 90th percentile.
+    pub p90: f64,
+    /// 95th percentile.
+    pub p95: f64,
+    /// 99th percentile.
+    pub p99: f64,
+    /// 99.9th percentile.
+    pub p999: f64,
+    /// Minimum value.
+    pub min: f64,
+    /// Maximum value.
+    pub max: f64,
+    /// Standard deviation.
+    pub std_dev: f64,
+    /// Coefficient of variation (std_dev / mean).
+    pub cv: f64,
+}
+
+impl Stats {
+    /// Computes statistics from a slice of f64 measurements (in nanoseconds).
+    pub fn from_measurements(data: &[f64]) -> Self {
+        if data.is_empty() {
+            return Self::empty();
+        }
+
+        let n = data.len() as f64;
+        let mean = data.iter().sum::<f64>() / n;
+
+        let mut sorted = data.to_vec();
+        sorted.sort_by(|a, b| a.partial_cmp(b).unwrap());
+
+        let percentile = |p: f64| -> f64 {
+            let idx = ((p / 100.0) * (sorted.len() - 1) as f64) as usize;
+            sorted[idx.min(sorted.len() - 1)]
+        };
+
+        let variance: f64 = data.iter().map(|x| (x - mean).powi(2)).sum::<f64>() / n;
+        let std_dev = variance.sqrt();
+
+        Self {
+            count: data.len() as u64,
+            mean,
+            median: percentile(50.0),
+            p90: percentile(90.0),
+            p95: percentile(95.0),
+            p99: percentile(99.0),
+            p999: percentile(99.9),
+            min: *sorted.first().unwrap(),
+            max: *sorted.last().unwrap(),
+            std_dev,
+            cv: if mean > 0.0 { std_dev / mean } else { 0.0 },
+        }
+    }
+
+    /// Creates empty statistics.
+    pub fn empty() -> Self {
+        Self {
+            count: 0,
+            mean: 0.0,
+            median: 0.0,
+            p90: 0.0,
+            p95: 0.0,
+            p99: 0.0,
+            p999: 0.0,
+            min: 0.0,
+            max: 0.0,
+            std_dev: 0.0,
+            cv: 0.0,
+        }
+    }
+
+    /// Formats the stats as a human-readable string.
+    pub fn format(&self) -> String {
+        format!(
+            "n={} mean={:.1}ns median={:.1}ns p95={:.1}ns p99={:.1}ns min={:.1}ns max={:.1}ns stddev={:.1}ns cv={:.2}%",
+            self.count, self.mean, self.median, self.p95, self.p99, self.min, self.max, self.std_dev, self.cv * 100.0
+        )
+    }
+}
